// Express Router
const express = require('express');
const app = express();
module.exports = router;
const router = require('router');
const router = express.Router();


// Define a router for the URL
const PORT = 3000;

// Express router
app.get('/', (req, res)=> {
        res.send("Users API");
} );

    // GET ROUTE -> used for READ DATA from the server
    app.get('/self_learn18/express-learning/node_modules/running.js', (req, res)=> {
        res.json({
            message: "GET request to the all Products",
        });
    });


    // POST ROUTE -> used for Create data to the server by data 
    app.post("/products", (req, res) => {
        // store data
        const data = req.body;

        res.json({
                message: "POST request create succesfully...!",
                product: data,

        });
    });


    // PUT ROUTE -> used for Update data to the server by id
    app.put("/prodcuts/:id", (req, res)=> {
            // store data for update
            const id = req.params.id;
                res.json({
                        message: "Products upddated succesfully...!",
                        id: id,
                });
    });

    
    // DELETE ROUTE -> used for Delete data to the server by id
    app.delete("/products/:id", (req, res) => {
            res.json({
                message: "Products deleted succesfully...!",
                id: req.params.id,
            })
    });



    // ROUTE PARAMATER -> usef for get data route by id

    app.get("/products/:id", (req, res)=> {
            
            console.log(req.params.id);

            res.send("Products id : " + req.params.id);
    });


        // Query Parameter ->Used for get data by query paramter

    app.get("/search/:name", (req, res) => {
        const keyword = req.params.name;
        
        res.json({
            search: keyword,
        })
    });








app.listen(PORT, () => {
        console.log("Server is Running...!"+ PORT);
});
